import { getTicks } from '@visx/scale';
import type { ScaleTime } from 'd3-scale';

import { DivAxisWrapper } from './DivAxisWrapper.js';
import {
  TickPrimitiveValue,
  TickValueFormatter,
} from '../../../types/tick-value.js';
import { formatDateTicks } from '../../../utils/format-date-ticks.js';
import { getTickValues } from '../../../utils/format-value.js';
import { getGanttHorizontalTimeAxisNumTicks } from '../../../utils/ticks.js';
import { AxisTableHeader } from '../AxisTableHeader.js';
import { axisFontProps } from '../constants.js';
import { getTickLabelPropsForGanttAxis } from '../utils/get-tick-label-props.js';

/**
 * @internal
 */
export interface TimeTableHeaderAxisProps {
  scale: ScaleTime<number, number>;
  containerWidth: number;
  containerHeight: number;
  stroke?: string;
  min?: number;
  max?: number;
}

/**
 * @internal
 */
export const TimeTableHeaderAxis = (props: TimeTableHeaderAxisProps) => {
  const { scale, containerWidth, containerHeight, stroke, min, max } = props;

  const numTicks = getGanttHorizontalTimeAxisNumTicks(containerWidth);
  const ticks = getTicks(scale, numTicks) as TickPrimitiveValue[];
  const tickValues = getTickValues(
    ticks,
    formatDateTicks as TickValueFormatter,
  );
  const tickFormat = (_: unknown, index: number) => tickValues[index];

  return (
    <DivAxisWrapper
      divAxisStyle={axisFontProps}
      ticks={tickValues}
      isTickVertical
    >
      <AxisTableHeader
        role="graphics-symbol"
        aria-label="time axis tableheader"
        scale={scale}
        containerSize={containerWidth}
        height={containerHeight}
        numTicks={numTicks}
        tickValues={ticks}
        tickLabelProps={getTickLabelPropsForGanttAxis(min, max)}
        tickFormat={tickFormat}
        stroke={stroke}
      />
    </DivAxisWrapper>
  );
};

TimeTableHeaderAxis['displayName'] = 'TimeTableHeaderAxis';
